// // This module decrements a 4-bit counter on each clock cycle when enabled, and resets to zero when the reset signal is asserted.
module counter (  
    input clk,  
    input reset,  
    input enable,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 4'b0000;  
        else if (enable)  
            count <= count + 1;  
    end  
endmodule
